function fmt(n){n=Math.round(n*100)/100;return '$'+(n%1===0?n.toLocaleString('en-US'):n.toFixed(2));}
function pISO(s){const p=s.split('-').map(Number);return new Date(p[0],p[1]-1,p[2]);}
